import { GoogleGenAI, GenerateContentResponse, Type, Part, Content, FunctionDeclaration } from "@google/genai";
import { ChatMessage, QuizQuestion, Flashcard, CodeExplanation, NoraSession } from '../types';
import { GEMINI_MODEL } from '../constants';

// FIX: Initialize the GoogleGenAI client with the API key from environment variables as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to build chat history for the API.
// Note: This version doesn't support images in history due to the app's state design
// (storing blob URLs instead of reusable data).
const buildChatHistory = (history: ChatMessage[]): Content[] => {
    if (!history || history.length === 0) {
        return [];
    }

    const cleanHistory: ChatMessage[] = [];

    // 1. Ensure roles alternate, keeping the last message of a consecutive sequence.
    // Also filter out partial messages from voice input.
    for (const msg of history) {
        if (msg.isPartial) continue;

        if (cleanHistory.length > 0 && cleanHistory[cleanHistory.length - 1].role === msg.role) {
            cleanHistory[cleanHistory.length - 1] = msg;
        } else {
            cleanHistory.push(msg);
        }
    }

    // 2. Convert to API format and handle non-textual content.
    const processedHistory = cleanHistory.map(msg => {
        let text = msg.text || '';

        // Create textual representation for special content types if no text is available.
        if (!msg.text) {
            if (msg.quiz) text = `[System: A quiz was generated for the user.]`;
            else if (msg.flashcards) text = `[System: Flashcards were generated for the user.]`;
            else if (msg.imageUrl) text = msg.role === 'model' 
                ? `[System: An image was generated.]`
                : `[System: An image was sent by the user.]`;
        }

        // If still empty, skip.
        if (!text.trim()) return null;

        return {
            role: msg.role,
            parts: [{ text: text }]
        };
    }).filter((msg): msg is Content => msg !== null);

    // 3. The API expects conversations to start with a 'user' role.
    if (processedHistory.length > 0 && processedHistory[0].role === 'model') {
        processedHistory.shift();
    }

    return processedHistory;
};

// Stateless implementation of the tutor chat to avoid state management errors.
export const generateTutorResponseStream = async (
  prompt: string,
  language: string,
  history: ChatMessage[],
  image?: { mimeType: string; data: string; }
): Promise<AsyncGenerator<string>> => {

  const userParts: Part[] = [{ text: prompt }];
  if (image) {
      userParts.push({ inlineData: { mimeType: image.mimeType, data: image.data } });
  }
  const userMessage: Content = { role: 'user', parts: userParts };

  const contents = [...buildChatHistory(history), userMessage];

  const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: contents,
      config: {
          systemInstruction: `You are a friendly and encouraging personal tutor. Your goal is to explain complex subjects in a simple, easy-to-understand way. All your responses must be in ${language}. Use relevant examples and analogies. Do not use markdown formatting like asterisks, underscores, or backticks for emphasis or code.`,
      }
  });

  async function* streamGenerator(): AsyncGenerator<string> {
    for await (const chunk of responseStream) {
      yield chunk.text;
    }
  }

  return streamGenerator();
};

const NORA_SYSTEM_INSTRUCTION = (notes: string) => `You are an expert study assistant called NORA (Note-Oriented Reference Assistant). Your knowledge is strictly based on the following notes. Do not use outside information. When asked to generate a quiz or flashcards, respond only with the requested JSON. When asked a question, answer it based on the notes. Your text responses should be clean and should not contain markdown formatting. NOTES:\n\n---\n${notes}\n---`;

const buildNoraContent = (session: NoraSession, prompt: string, image?: { mimeType: string; data: string; }): Content[] => {
    const userParts: Part[] = [{ text: prompt }];
    if (image) {
        userParts.push({ inlineData: { mimeType: image.mimeType, data: image.data } });
    }
    const userMessage: Content = { role: 'user', parts: userParts };
    return [...buildChatHistory(session.history), userMessage];
};


export const generateNoraTextStream = async (session: NoraSession, prompt: string, image?: { mimeType: string; data: string; }): Promise<AsyncGenerator<string>> => {
    const responseStream = await ai.models.generateContentStream({
        model: GEMINI_MODEL,
        contents: buildNoraContent(session, prompt, image),
        config: {
            systemInstruction: NORA_SYSTEM_INSTRUCTION(session.notes)
        }
    });

    async function* streamGenerator(): AsyncGenerator<string> {
        for await (const chunk of responseStream) {
            yield chunk.text;
        }
    }

    return streamGenerator();
};

export const generateNoraJson = async (session: NoraSession, prompt: string, schema: any, image?: { mimeType: string; data: string; }): Promise<any> => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: buildNoraContent(session, prompt, image),
        config: {
            systemInstruction: NORA_SYSTEM_INSTRUCTION(session.notes),
            responseMimeType: 'application/json',
            responseSchema: schema
        }
    });
    return JSON.parse(response.text);
};


export const generateImage = async(prompt: string): Promise<string> => {
    const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: prompt,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/png',
          aspectRatio: '16:9',
        },
    });

    const base64ImageBytes: string = response.generatedImages[0].image.imageBytes;
    return `data:image/png;base64,${base64ImageBytes}`;
};

export const generateNotesFromTranscription = async (transcription: string): Promise<string> => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: `Take the following transcription and convert it into structured, well-organized notes. Use headings, bullet points, and summaries where appropriate to make the information clear and easy to digest. Do not use markdown like asterisks or underscores for formatting.\n\nTranscription:\n${transcription}`,
    });
    return response.text;
};

export const explainCode = async (code: string, language: string): Promise<CodeExplanation[]> => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: `Explain the following ${language} code. Go through it line by line and provide a simple explanation for each line. The explanation text itself should be plain text, without any markdown formatting. Code:\n\n${code}`,
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        lineNumber: { type: Type.INTEGER },
                        code: { type: Type.STRING },
                        explanation: { type: Type.STRING }
                    },
                    required: ['lineNumber', 'code', 'explanation']
                }
            }
        }
    });
    return JSON.parse(response.text);
};

// --- RAM AGENT SERVICE ---

const RAM_SYSTEM_INSTRUCTION = `
You are "Ram", an intelligent voice assistant. 
IMPORTANT: You must always respond in TELUGU (తెలుగు) language.
You have access to tools to play songs on YouTube and open WhatsApp.
If the user asks to play a song, use the 'play_song' function.
If the user asks to open WhatsApp or contact someone, use the 'open_whatsapp' function.
If the user mentions taking a file, photo, or document to the website, trigger the 'open_whatsapp' function (as it handles contact) and mention in your Telugu response that you have opened WhatsApp and are ready for the file upload.
Be helpful, polite, and concise.
`;

const playSongTool: FunctionDeclaration = {
    name: "play_song",
    description: "Plays a song on YouTube based on the user's request.",
    parameters: {
        type: Type.OBJECT,
        properties: {
            song_name: {
                type: Type.STRING,
                description: "The name of the song or video to search for."
            }
        },
        required: ["song_name"]
    }
};

const openWhatsappTool: FunctionDeclaration = {
    name: "open_whatsapp",
    description: "Opens WhatsApp Web. Use this if the user wants to chat, contact someone, or transfer a file/photo.",
    parameters: {
        type: Type.OBJECT,
        properties: {
            contact_name: {
                type: Type.STRING,
                description: "The name of the person to contact (optional)."
            },
            action_type: {
                type: Type.STRING,
                description: "Type of action: 'chat' or 'file_transfer'"
            }
        },
        required: ["action_type"]
    }
};

export const runRamAgent = async (transcript: string) => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: transcript,
        config: {
            systemInstruction: RAM_SYSTEM_INSTRUCTION,
            tools: [{ functionDeclarations: [playSongTool, openWhatsappTool] }],
        }
    });

    return response;
};

import React, { useState, useEffect, useRef } from 'react';
import { runRamAgent } from '../../services/geminiService';
import { useSpeechToText } from '../../hooks/useSpeechToText';
import { MicrophoneIcon } from '../icons/MicrophoneIcon';
import Loader from '../ui/Loader';
import { SparklesIcon } from '../icons/SparklesIcon';

const RamAgent: React.FC = () => {
    const [isProcessing, setIsProcessing] = useState(false);
    const [responseText, setResponseText] = useState<string>('');
    const { isListening, transcript, startListening, stopListening, hasRecognitionSupport } = useSpeechToText();

    // Hidden file input for "take file" simulation
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Auto-process when silence implies command is done (simple debounce implementation or manual stop)
    // For this implementation, we will rely on manual stop or the user pausing, 
    // but to make it "Agent" like, we'll let the user toggle the mic.

    const handleAgentInteraction = async () => {
        if (!transcript.trim()) return;

        setIsProcessing(true);
        setResponseText(''); 

        try {
            const result = await runRamAgent(transcript);

            // Handle Function Calls
            const functionCalls = result.functionCalls;
            if (functionCalls && functionCalls.length > 0) {
                const call = functionCalls[0];
                const args = call.args as any;

                if (call.name === 'play_song') {
                    const song = args.song_name;
                    window.open(`https://www.youtube.com/results?search_query=${encodeURIComponent(song)}`, '_blank');
                } else if (call.name === 'open_whatsapp') {
                    // Open WhatsApp Web
                    window.open('https://web.whatsapp.com', '_blank');

                    // If the intent involved a file/photo, trigger our file uploader
                    if (args.action_type === 'file_transfer' || transcript.toLowerCase().includes('file') || transcript.toLowerCase().includes('photo')) {
                        setTimeout(() => {
                            if (fileInputRef.current) {
                                fileInputRef.current.click();
                            }
                        }, 1000);
                    }
                }
            }

            // Handle Text Response (Speak it)
            const text = result.text;
            if (text) {
                setResponseText(text);
                speakText(text);
            }

        } catch (error) {
            console.error("Ram Agent Error:", error);
            setResponseText("Sorry, something went wrong.");
        } finally {
            setIsProcessing(false);
        }
    };

    // When listening stops, process the transcript
    const prevListening = useRef(isListening);
    useEffect(() => {
        if (prevListening.current && !isListening && transcript) {
            handleAgentInteraction();
        }
        prevListening.current = isListening;
    }, [isListening, transcript]);

    const speakText = (text: string) => {
        if ('speechSynthesis' in window) {
            // Cancel any current speech
            window.speechSynthesis.cancel();

            const utterance = new SpeechSynthesisUtterance(text);
            // Try to set Telugu voice if available, otherwise browser default will try to read standard chars
            // Note: Not all OSs have a 'te-IN' voice installed by default.
            utterance.lang = 'te-IN'; 
            utterance.rate = 1.0;
            utterance.pitch = 1.0;
            window.speechSynthesis.speak(utterance);
        }
    };

    const toggleListening = () => {
        if (isListening) {
            stopListening();
        } else {
            setResponseText("నేను వింటున్నాను... (Listening...)");
            startListening();
        }
    };

    if (!hasRecognitionSupport) return null;

    return (
        <div className="mt-2 flex flex-col items-end w-64">
            {/* Agent Card */}
            <div className="bg-gradient-to-br from-orange-900/80 to-red-900/80 backdrop-blur-md border border-orange-500/30 p-3 rounded-xl shadow-lg w-full transition-all duration-300">
                <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2">
                        <div className="bg-orange-500 p-1 rounded-full">
                            <SparklesIcon className="w-4 h-4 text-white" />
                        </div>
                        <span className="font-bold text-orange-100 text-sm">Ram (Voice Agent)</span>
                    </div>
                    {isProcessing && <Loader size="sm" className="text-orange-300" />}
                </div>

                <div className="bg-black/20 rounded p-2 min-h-[40px] mb-2">
                    <p className="text-xs text-gray-200">
                        {isListening ? (
                            <span className="animate-pulse text-orange-300">Listening: {transcript}</span>
                        ) : (
                            responseText || "Namaskaram! How can I help?"
                        )}
                    </p>
                </div>

                <div className="flex justify-center">
                    <button
                        onClick={toggleListening}
                        className={`p-3 rounded-full transition-all duration-300 shadow-lg flex items-center gap-2
                            ${isListening 
                                ? 'bg-red-500 text-white animate-pulse ring-2 ring-red-300' 
                                : 'bg-orange-600 hover:bg-orange-500 text-white'
                            }`}
                    >
                        <MicrophoneIcon className="w-5 h-5" />
                        <span className="text-xs font-semibold">{isListening ? 'Stop' : 'Ask Ram'}</span>
                    </button>
                </div>
            </div>

            {/* Hidden Input for File Simulation */}
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                onChange={() => alert("File selected! (Simulation complete)")}
            />
        </div>
    );
};

export default RamAgent;

