// FIX: Import React to provide the React namespace for types like React.Dispatch.
import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Blob } from '@google/genai';
import { ChatMessage } from '../types';

// FIX: Add global declaration for webkitAudioContext to fix TypeScript errors and ensure cross-browser compatibility.
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

// FIX: Initialize the GoogleGenAI client with the API key from environment variables as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// FIX: Define LiveSession type helper since it's not exported directly in the current SDK version.
type LiveSession = Awaited<ReturnType<InstanceType<typeof GoogleGenAI>['live']['connect']>>;

// Helper function to resample an audio buffer to a target sample rate.
const resampleBuffer = (inputBuffer: Float32Array, fromSampleRate: number, toSampleRate: number): Float32Array => {
    if (fromSampleRate === toSampleRate) {
        return inputBuffer;
    }

    const inputLength = inputBuffer.length;
    const outputLength = Math.round(inputLength * toSampleRate / fromSampleRate);
    const outputBuffer = new Float32Array(outputLength);

    if (inputLength === 0 || outputLength === 0) {
        return outputBuffer;
    }

    if (outputLength === 1) {
        let sum = 0;
        for (let i = 0; i < inputLength; i++) {
            sum += inputBuffer[i];
        }
        outputBuffer[0] = sum / inputLength;
        return outputBuffer;
    }

    const ratio = (inputLength - 1) / (outputLength - 1);

    for (let i = 0; i < outputLength; i++) {
        const index = i * ratio;
        const low = Math.floor(index);
        const high = Math.ceil(index);

        if (low === high) {
            outputBuffer[i] = inputBuffer[low];
        } else {
            const weight = index - low;
            outputBuffer[i] = inputBuffer[low] * (1 - weight) + inputBuffer[high] * weight;
        }
    }
    return outputBuffer;
};


// Base64 and Audio Decoding/Encoding Helpers
const decode = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

const encode = (bytes: Uint8Array) => {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
};

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export type ConversationState = 'idle' | 'listening' | 'processing' | 'speaking';

interface UseVoiceConversationProps {
  systemInstruction: string;
  onUpdateHistory: React.Dispatch<React.SetStateAction<ChatMessage[]>>;
  initialHistory: ChatMessage[];
  voice: string;
}

export const useVoiceConversation = ({ systemInstruction, onUpdateHistory, voice }: UseVoiceConversationProps) => {
  const [conversationState, setConversationState] = useState<ConversationState>('idle');
  const [error, setError] = useState<string | null>(null);

  const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const mediaStreamSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const nextStartTimeRef = useRef(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isStoppingRef = useRef(false);

  const cleanup = useCallback(async () => {
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }
    if (mediaStreamSourceRef.current) {
        mediaStreamSourceRef.current.disconnect();
        mediaStreamSourceRef.current = null;
    }
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }
    audioSourcesRef.current.forEach(source => source.stop());
    audioSourcesRef.current.clear();
    nextStartTimeRef.current = 0;

    const closePromises = [];
    if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
        closePromises.push(inputAudioContextRef.current.close());
    }
    if (outputAudioContextRef.current && outputAudioContextRef.current.state !== 'closed') {
        closePromises.push(outputAudioContextRef.current.close());
    }

    if(closePromises.length > 0) {
        await Promise.all(closePromises.map(p => p.catch(console.error)));
    }

    setConversationState('idle');
  }, []);

  const stopConversation = useCallback(async () => {
    if (isStoppingRef.current) {
      return;
    }
    isStoppingRef.current = true;

    if (sessionPromiseRef.current) {
      try {
        const session = await sessionPromiseRef.current;
        session.close();
      } catch (e) {
        console.error("Error closing session:", e);
      }
      sessionPromiseRef.current = null;
    }
    await cleanup();
    isStoppingRef.current = false;
  }, [cleanup]);


  const startConversation = useCallback(async () => {
    if (conversationState !== 'idle') return;

    setError(null);
    setConversationState('listening');

    try {
        inputAudioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        outputAudioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });

        mediaStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

        let currentInputTranscription = '';
        let currentOutputTranscription = '';

        sessionPromiseRef.current = ai.live.connect({
            model: 'gemini-2.5-flash-native-audio-preview-12-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice } } },
                systemInstruction,
                outputAudioTranscription: {},
                inputAudioTranscription: {},
            },
            callbacks: {
                onopen: () => {
                    const source = inputAudioContextRef.current!.createMediaStreamSource(mediaStreamRef.current!);
                    mediaStreamSourceRef.current = source;
                    const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(1024, 1, 1);
                    scriptProcessorRef.current = scriptProcessor;

                    scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                        const inputBuffer = audioProcessingEvent.inputBuffer;
                        const rawPcmData = inputBuffer.getChannelData(0);
                        const resampledData = resampleBuffer(rawPcmData, inputBuffer.sampleRate, 16000);
                        const pcmBlob = createBlob(resampledData);

                        if (sessionPromiseRef.current) {
                           sessionPromiseRef.current.then((session) => {
                             session.sendRealtimeInput({ media: pcmBlob });
                           });
                        }
                    };
                    source.connect(scriptProcessor);
                    scriptProcessor.connect(inputAudioContextRef.current!.destination);
                },
                onmessage: async (message: LiveServerMessage) => {
                    if (message.serverContent?.inputTranscription) {
                        currentInputTranscription += message.serverContent.inputTranscription.text;
                        onUpdateHistory(prevHistory => {
                            const newHistory = [...prevHistory];
                            const lastMsg = newHistory[newHistory.length - 1];
                            if (lastMsg?.role === 'user' && lastMsg.isPartial) {
                                lastMsg.text = currentInputTranscription;
                            } else {
                                newHistory.push({ role: 'user', text: currentInputTranscription, isPartial: true });
                            }
                            return newHistory;
                        });
                    }
                    if (message.serverContent?.outputTranscription) {
                        setConversationState('speaking');
                        currentOutputTranscription += message.serverContent.outputTranscription.text;
                        onUpdateHistory(prevHistory => {
                            const newHistory = [...prevHistory];
                            const lastMsg = newHistory[newHistory.length - 1];
                            if (lastMsg?.role === 'model' && lastMsg.isPartial) {
                                lastMsg.text = currentOutputTranscription;
                            } else {
                                newHistory.push({ role: 'model', text: currentOutputTranscription, isPartial: true });
                            }
                            return newHistory;
                        });
                    }
                    if (message.serverContent?.turnComplete) {
                        onUpdateHistory(prevHistory => {
                            const newHistory = [...prevHistory];
                            const finalUserMsg = newHistory.find(m => m.role === 'user' && m.isPartial);
                            if (finalUserMsg) finalUserMsg.isPartial = false;

                            const finalModelMsg = newHistory.find(m => m.role === 'model' && m.isPartial);
                            if (finalModelMsg) finalModelMsg.isPartial = false;

                            return newHistory;
                        });

                        currentInputTranscription = '';
                        currentOutputTranscription = '';
                        setConversationState('listening');
                    }

                    const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                    if (base64Audio && outputAudioContextRef.current) {
                        const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContextRef.current, 24000, 1);
                        const source = outputAudioContextRef.current.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(outputAudioContextRef.current.destination);

                        source.addEventListener('ended', () => {
                            audioSourcesRef.current.delete(source);
                        });

                        const currentTime = outputAudioContextRef.current.currentTime;
                        const startTime = Math.max(currentTime, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + audioBuffer.duration;
                        audioSourcesRef.current.add(source);
                    }
                },
                onerror: (e: ErrorEvent) => {
                    console.error("Session error:", e);
                    setError('A connection error occurred.');
                    stopConversation();
                },
                onclose: (e: CloseEvent) => {
                    stopConversation();
                },
            },
        });
        await sessionPromiseRef.current;
    } catch (e) {
        console.error("Failed to start conversation:", e);
        setError('Could not access microphone. Please check permissions.');
        cleanup();
    }
  }, [conversationState, systemInstruction, onUpdateHistory, cleanup, stopConversation, voice]);

  useEffect(() => {
      return () => {
          stopConversation();
      }
  }, [stopConversation]);

  return { conversationState, error, startConversation, stopConversation };
};

import { GoogleGenAI, GenerateContentResponse, Type, Part, Content, FunctionDeclaration } from "@google/genai";
import { ChatMessage, QuizQuestion, Flashcard, CodeExplanation, NoraSession } from '../types';
import { GEMINI_MODEL } from '../constants';

// FIX: Initialize the GoogleGenAI client with the API key from environment variables as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to build chat history for the API.
// Note: This version doesn't support images in history due to the app's state design
// (storing blob URLs instead of reusable data).
const buildChatHistory = (history: ChatMessage[]): Content[] => {
    if (!history || history.length === 0) {
        return [];
    }

    const cleanHistory: ChatMessage[] = [];

    // 1. Ensure roles alternate, keeping the last message of a consecutive sequence.
    // Also filter out partial messages from voice input.
    for (const msg of history) {
        if (msg.isPartial) continue;

        if (cleanHistory.length > 0 && cleanHistory[cleanHistory.length - 1].role === msg.role) {
            cleanHistory[cleanHistory.length - 1] = msg;
        } else {
            cleanHistory.push(msg);
        }
    }

    // 2. Convert to API format and handle non-textual content.
    // FIX: Explicitly return Content | null to satisfy the type predicate in filter.
    const processedHistory = cleanHistory.map((msg): Content | null => {
        let text = msg.text || '';

        // Create textual representation for special content types if no text is available.
        if (!msg.text) {
            if (msg.quiz) text = `[System: A quiz was generated for the user.]`;
            else if (msg.flashcards) text = `[System: Flashcards were generated for the user.]`;
            else if (msg.imageUrl) text = msg.role === 'model' 
                ? `[System: An image was generated.]`
                : `[System: An image was sent by the user.]`;
        }

        // If still empty, skip.
        if (!text.trim()) return null;

        return {
            role: msg.role,
            parts: [{ text: text }]
        };
    }).filter((msg): msg is Content => msg !== null);

    // 3. The API expects conversations to start with a 'user' role.
    if (processedHistory.length > 0 && processedHistory[0].role === 'model') {
        processedHistory.shift();
    }

    return processedHistory;
};

// Stateless implementation of the tutor chat to avoid state management errors.
export const generateTutorResponseStream = async (
  prompt: string,
  language: string,
  history: ChatMessage[],
  image?: { mimeType: string; data: string; }
): Promise<AsyncGenerator<string>> => {

  const userParts: Part[] = [{ text: prompt }];
  if (image) {
      userParts.push({ inlineData: { mimeType: image.mimeType, data: image.data } });
  }
  const userMessage: Content = { role: 'user', parts: userParts };

  const contents = [...buildChatHistory(history), userMessage];

  const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents: contents,
      config: {
          systemInstruction: `You are a friendly and encouraging personal tutor. Your goal is to explain complex subjects in a simple, easy-to-understand way. All your responses must be in ${language}. Use relevant examples and analogies. Do not use markdown formatting like asterisks, underscores, or backticks for emphasis or code.`,
      }
  });

  async function* streamGenerator(): AsyncGenerator<string> {
    for await (const chunk of responseStream) {
      yield chunk.text;
    }
  }

  return streamGenerator();
};

const NORA_SYSTEM_INSTRUCTION = (notes: string) => `You are an expert study assistant called NORA (Note-Oriented Reference Assistant). Your knowledge is strictly based on the following notes. Do not use outside information. When asked to generate a quiz or flashcards, respond only with the requested JSON. When asked a question, answer it based on the notes. Your text responses should be clean and should not contain markdown formatting. NOTES:\n\n---\n${notes}\n---`;

const buildNoraContent = (session: NoraSession, prompt: string, image?: { mimeType: string; data: string; }): Content[] => {
    const userParts: Part[] = [{ text: prompt }];
    if (image) {
        userParts.push({ inlineData: { mimeType: image.mimeType, data: image.data } });
    }
    const userMessage: Content = { role: 'user', parts: userParts };
    return [...buildChatHistory(session.history), userMessage];
};


export const generateNoraTextStream = async (session: NoraSession, prompt: string, image?: { mimeType: string; data: string; }): Promise<AsyncGenerator<string>> => {
    const responseStream = await ai.models.generateContentStream({
        model: GEMINI_MODEL,
        contents: buildNoraContent(session, prompt, image),
        config: {
            systemInstruction: NORA_SYSTEM_INSTRUCTION(session.notes)
        }
    });

    async function* streamGenerator(): AsyncGenerator<string> {
        for await (const chunk of responseStream) {
            yield chunk.text;
        }
    }

    return streamGenerator();
};

export const generateNoraJson = async (session: NoraSession, prompt: string, schema: any, image?: { mimeType: string; data: string; }): Promise<any> => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: buildNoraContent(session, prompt, image),
        config: {
            systemInstruction: NORA_SYSTEM_INSTRUCTION(session.notes),
            responseMimeType: 'application/json',
            responseSchema: schema
        }
    });
    return JSON.parse(response.text);
};


export const generateImage = async(prompt: string): Promise<string> => {
    const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: prompt,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/png',
          aspectRatio: '16:9',
        },
    });

    const base64ImageBytes: string = response.generatedImages[0].image.imageBytes;
    return `data:image/png;base64,${base64ImageBytes}`;
};

export const generateNotesFromTranscription = async (transcription: string): Promise<string> => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: `Take the following transcription and convert it into structured, well-organized notes. Use headings, bullet points, and summaries where appropriate to make the information clear and easy to digest. Do not use markdown like asterisks or underscores for formatting.\n\nTranscription:\n${transcription}`,
    });
    return response.text;
};

export const explainCode = async (code: string, language: string): Promise<CodeExplanation[]> => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: `Explain the following ${language} code. Go through it line by line and provide a simple explanation for each line. The explanation text itself should be plain text, without any markdown formatting. Code:\n\n${code}`,
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        lineNumber: { type: Type.INTEGER },
                        code: { type: Type.STRING },
                        explanation: { type: Type.STRING }
                    },
                    required: ['lineNumber', 'code', 'explanation']
                }
            }
        }
    });
    return JSON.parse(response.text);
};

