import React, { useState, useEffect, useRef } from 'react';
import { runRamAgent } from '../../services/geminiService';
import { useSpeechToText } from '../../hooks/useSpeechToText';
import { MicrophoneIcon } from '../icons/MicrophoneIcon';
import Loader from '../ui/Loader';
import { SparklesIcon } from '../icons/SparklesIcon';
import { FeatureId } from '../../constants';

interface RamAgentProps {
    onNavigate: (featureId: FeatureId) => void;
}

const RamAgent: React.FC<RamAgentProps> = ({ onNavigate }) => {
    const [isProcessing, setIsProcessing] = useState(false);
    const [responseText, setResponseText] = useState<string>('');
    const { isListening, transcript, startListening, stopListening, hasRecognitionSupport } = useSpeechToText();

    // Hidden file input for "take file" simulation
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Auto-process when silence implies command is done (simple debounce implementation or manual stop)
    // For this implementation, we will rely on manual stop or the user pausing, 
    // but to make it "Agent" like, we'll let the user toggle the mic.

    const handleAgentInteraction = async () => {
        if (!transcript.trim()) return;

        setIsProcessing(true);
        setResponseText(''); 

        try {
            const result = await runRamAgent(transcript);

            // Handle Function Calls
            const functionCalls = result.functionCalls;
            if (functionCalls && functionCalls.length > 0) {
                const call = functionCalls[0];
                const args = call.args as any;

                if (call.name === 'play_song') {
                    const song = args.song_name;
                    window.open(`https://www.youtube.com/results?search_query=${encodeURIComponent(song)}`, '_blank');
                } else if (call.name === 'open_whatsapp') {
                    // Open WhatsApp Web
                    window.open('https://web.whatsapp.com', '_blank');

                    // If the intent involved a file/photo, trigger our file uploader
                    if (args.action_type === 'file_transfer' || transcript.toLowerCase().includes('file') || transcript.toLowerCase().includes('photo')) {
                        setTimeout(() => {
                            if (fileInputRef.current) {
                                fileInputRef.current.click();
                            }
                        }, 1000);
                    }
                } else if (call.name === 'navigate_to_feature') {
                    const featureId = args.feature_id;
                    if (featureId === 'tutor') {
                        onNavigate(FeatureId.TUTOR);
                    } else if (featureId === 'exam-prep') {
                        onNavigate(FeatureId.EXAM_PREP);
                    } else if (featureId === 'coding-mentor') {
                        onNavigate(FeatureId.CODING_MENTOR);
                    }
                }
            }

            // Handle Text Response (Speak it)
            const text = result.text;
            if (text) {
                setResponseText(text);
                speakText(text);
            }

        } catch (error) {
            console.error("Ram Agent Error:", error);
            setResponseText("Sorry, something went wrong.");
        } finally {
            setIsProcessing(false);
        }
    };

    // When listening stops, process the transcript
    const prevListening = useRef(isListening);
    useEffect(() => {
        if (prevListening.current && !isListening && transcript) {
            handleAgentInteraction();
        }
        prevListening.current = isListening;
    }, [isListening, transcript]);

    const speakText = (text: string) => {
        if ('speechSynthesis' in window) {
            // Cancel any current speech
            window.speechSynthesis.cancel();

            const utterance = new SpeechSynthesisUtterance(text);
            // Try to set Telugu voice if available, otherwise browser default will try to read standard chars
            // Note: Not all OSs have a 'te-IN' voice installed by default.
            utterance.lang = 'te-IN'; 
            utterance.rate = 1.0;
            utterance.pitch = 1.0;
            window.speechSynthesis.speak(utterance);
        }
    };

    const toggleListening = () => {
        if (isListening) {
            stopListening();
        } else {
            setResponseText("నేను వింటున్నాను... (Listening...)");
            startListening();
        }
    };

    if (!hasRecognitionSupport) return null;

    return (
        <div className="mt-2 flex flex-col items-end w-64">
            {/* Agent Card */}
            <div className="bg-gradient-to-br from-orange-900/80 to-red-900/80 backdrop-blur-md border border-orange-500/30 p-3 rounded-xl shadow-lg w-full transition-all duration-300">
                <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2">
                        <div className="bg-orange-500 p-1 rounded-full">
                            <SparklesIcon className="w-4 h-4 text-white" />
                        </div>
                        <span className="font-bold text-orange-100 text-sm">Ram (Voice Agent)</span>
                    </div>
                    {isProcessing && <Loader size="sm" className="text-orange-300" />}
                </div>

                <div className="bg-black/20 rounded p-2 min-h-[40px] mb-2">
                    <p className="text-xs text-gray-200">
                        {isListening ? (
                            <span className="animate-pulse text-orange-300">Listening: {transcript}</span>
                        ) : (
                            responseText || "Namaskaram! How can I help?"
                        )}
                    </p>
                </div>

                <div className="flex justify-center">
                    <button
                        onClick={toggleListening}
                        className={`p-3 rounded-full transition-all duration-300 shadow-lg flex items-center gap-2
                            ${isListening 
                                ? 'bg-red-500 text-white animate-pulse ring-2 ring-red-300' 
                                : 'bg-orange-600 hover:bg-orange-500 text-white'
                            }`}
                    >
                        <MicrophoneIcon className="w-5 h-5" />
                        <span className="text-xs font-semibold">{isListening ? 'Stop' : 'Ask Ram'}</span>
                    </button>
                </div>
            </div>

            {/* Hidden Input for File Simulation */}
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                onChange={() => alert("File selected! (Simulation complete)")}
            />
        </div>
    );
};

export default RamAgent;

