import { useState, useRef, useEffect, useCallback } from 'react';

interface SpeechRecognition {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  onresult: (event: any) => void;
  onerror: (event: any) => void;
  onend: () => void;
  start: () => void;
  stop: () => void;
}

declare global {
  interface Window {
    SpeechRecognition: new () => SpeechRecognition;
    webkitSpeechRecognition: new () => SpeechRecognition;
  }
}

export const useSpeechToText = () => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSupported, setIsSupported] = useState(false);
  const recognitionRef = useRef<SpeechRecognition | null>(null);

  useEffect(() => {
    if (typeof window === 'undefined') return;

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('Speech recognition not supported in this browser.');
      setIsSupported(false);
      return;
    }

    setIsSupported(true);

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'en-US';

    recognition.onresult = (event: any) => {
      let finalTranscript = '';
      let interimTranscript = '';

      for (let i = 0; i < event.results.length; ++i) {
        if (event.results[i].isFinal) {
          finalTranscript += event.results[i][0].transcript;
        } else {
          interimTranscript += event.results[i][0].transcript;
        }
      }
      setTranscript(finalTranscript + interimTranscript);
    };

    recognition.onerror = (event: any) => {
      // Ignore 'no-speech' errors as they are common when silence occurs
      if (event.error !== 'no-speech') {
          setError(`Speech recognition error: ${event.error}`);
      }
      setIsListening(false);
    };

    recognition.onend = () => {
        setIsListening(false);
    };

    recognitionRef.current = recognition;

    return () => {
        if (recognitionRef.current) {
            recognitionRef.current.stop();
        }
    }
  }, []);

  const startListening = useCallback(() => {
    if (recognitionRef.current && !isListening) {
      setTranscript('');
      setError(null);
      try {
        recognitionRef.current.start();
        setIsListening(true);
      } catch (e) {
        console.error("Failed to start speech recognition:", e);
      }
    }
  }, [isListening]);

  const stopListening = useCallback(() => {
    if (recognitionRef.current && isListening) {
      recognitionRef.current.stop();
      setIsListening(false);
    }
  }, [isListening]);

  return { isListening, transcript, error, startListening, stopListening, hasRecognitionSupport: isSupported };
};

import React, { useState, useEffect, useRef } from 'react';
import { runRamAgent } from '../../services/geminiService';
import { useSpeechToText } from '../../hooks/useSpeechToText';
import { MicrophoneIcon } from '../icons/MicrophoneIcon';
import Loader from '../ui/Loader';
import { SparklesIcon } from '../icons/SparklesIcon';
import { FeatureId } from '../../constants';

interface RamAgentProps {
    onNavigate: (featureId: FeatureId) => void;
}

const RamAgent: React.FC<RamAgentProps> = ({ onNavigate }) => {
    const [isProcessing, setIsProcessing] = useState(false);
    const [responseText, setResponseText] = useState<string>('');
    const { isListening, transcript, startListening, stopListening, hasRecognitionSupport } = useSpeechToText();

    // Hidden file input for "take file" simulation
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Auto-process when silence implies command is done (simple debounce implementation or manual stop)
    // For this implementation, we will rely on manual stop or the user pausing, 
    // but to make it "Agent" like, we'll let the user toggle the mic.

    const handleAgentInteraction = async () => {
        if (!transcript.trim()) return;

        setIsProcessing(true);
        setResponseText(''); 

        try {
            const result = await runRamAgent(transcript);

            // Handle Function Calls
            const functionCalls = result.functionCalls;
            if (functionCalls && functionCalls.length > 0) {
                const call = functionCalls[0];
                const args = call.args as any;

                if (call.name === 'play_song') {
                    const song = args.song_name;
                    window.open(`https://www.youtube.com/results?search_query=${encodeURIComponent(song)}`, '_blank');
                } else if (call.name === 'open_whatsapp') {
                    // Open WhatsApp Web
                    window.open('https://web.whatsapp.com', '_blank');

                    // If the intent involved a file/photo, trigger our file uploader
                    if (args.action_type === 'file_transfer' || transcript.toLowerCase().includes('file') || transcript.toLowerCase().includes('photo')) {
                        setTimeout(() => {
                            if (fileInputRef.current) {
                                fileInputRef.current.click();
                            }
                        }, 1000);
                    }
                } else if (call.name === 'navigate_to_feature') {
                    const featureId = args.feature_id;
                    if (featureId === 'tutor') {
                        onNavigate(FeatureId.TUTOR);
                    } else if (featureId === 'exam-prep') {
                        onNavigate(FeatureId.EXAM_PREP);
                    } else if (featureId === 'coding-mentor') {
                        onNavigate(FeatureId.CODING_MENTOR);
                    }
                }
            }

            // Handle Text Response (Speak it)
            const text = result.text;
            if (text) {
                setResponseText(text);
                speakText(text);
            }

        } catch (error) {
            console.error("Ram Agent Error:", error);
            setResponseText("Sorry, something went wrong.");
        } finally {
            setIsProcessing(false);
        }
    };

    // When listening stops, process the transcript
    const prevListening = useRef(isListening);
    useEffect(() => {
        if (prevListening.current && !isListening && transcript) {
            handleAgentInteraction();
        }
        prevListening.current = isListening;
    }, [isListening, transcript]);

    const speakText = (text: string) => {
        if ('speechSynthesis' in window) {
            // Cancel any current speech
            window.speechSynthesis.cancel();

            const utterance = new SpeechSynthesisUtterance(text);
            // Try to set Telugu voice if available, otherwise browser default will try to read standard chars
            // Note: Not all OSs have a 'te-IN' voice installed by default.
            utterance.lang = 'te-IN'; 
            utterance.rate = 1.0;
            utterance.pitch = 1.0;
            window.speechSynthesis.speak(utterance);
        }
    };

    const toggleListening = () => {
        if (isListening) {
            stopListening();
        } else {
            setResponseText("నేను వింటున్నాను... (Listening...)");
            startListening();
        }
    };

    // If not supported, we show a disabled state instead of returning null
    if (!hasRecognitionSupport) {
        return (
            <div className="mt-2 flex flex-col items-end w-64 opacity-70">
                 <div className="bg-gradient-to-br from-gray-800 to-gray-900 border border-gray-700 p-3 rounded-xl shadow-lg w-full">
                     <p className="text-xs text-red-400 text-center">Voice not supported in this browser.</p>
                 </div>
            </div>
        );
    }

    return (
        <div className="mt-2 flex flex-col items-end w-64 z-50 relative">
            {/* Agent Card */}
            <div className="bg-gradient-to-br from-orange-900/90 to-red-900/90 backdrop-blur-md border border-orange-500/30 p-3 rounded-xl shadow-2xl w-full transition-all duration-300">
                <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2">
                        <div className="bg-orange-500 p-1.5 rounded-full shadow-orange-500/50 shadow-md">
                            <SparklesIcon className="w-4 h-4 text-white" />
                        </div>
                        <span className="font-bold text-orange-100 text-sm">Ram (Voice Agent)</span>
                    </div>
                    {isProcessing && <Loader size="sm" className="text-orange-300" />}
                </div>

                <div className="bg-black/30 rounded p-2 min-h-[40px] mb-2 border border-white/5">
                    <p className="text-xs text-gray-200">
                        {isListening ? (
                            <span className="animate-pulse text-orange-300">Listening: {transcript}</span>
                        ) : (
                            responseText || "Namaskaram! How can I help?"
                        )}
                    </p>
                </div>

                <div className="flex justify-center">
                    <button
                        onClick={toggleListening}
                        className={`p-3 rounded-full transition-all duration-300 shadow-lg flex items-center gap-2 w-full justify-center
                            ${isListening 
                                ? 'bg-red-500 text-white animate-pulse ring-2 ring-red-300 shadow-red-500/50' 
                                : 'bg-gradient-to-r from-orange-600 to-red-600 hover:from-orange-500 hover:to-red-500 text-white shadow-orange-500/30'
                            }`}
                    >
                        <MicrophoneIcon className="w-5 h-5" />
                        <span className="text-xs font-semibold">{isListening ? 'Stop Listening' : 'Ask Ram'}</span>
                    </button>
                </div>
            </div>

            {/* Hidden Input for File Simulation */}
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                onChange={() => alert("File selected! (Simulation complete)")}
            />
        </div>
    );
};

export default RamAgent;

import { GoogleGenAI, GenerateContentResponse, Type, Part, Content, FunctionDeclaration } from "@google/genai";
import { ChatMessage, QuizQuestion, Flashcard, CodeExplanation, NoraSession } from '../types';
import { GEMINI_MODEL } from '../constants';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const buildChatHistory = (history: ChatMessage[]): Content[] => {
    if (!history || history.length === 0) return [];
    const cleanHistory: ChatMessage[] = [];
    for (const msg of history) {
        if (msg.isPartial) continue;
        if (cleanHistory.length > 0 && cleanHistory[cleanHistory.length - 1].role === msg.role) {
            cleanHistory[cleanHistory.length - 1] = msg;
        } else {
            cleanHistory.push(msg);
        }
    }
    return cleanHistory.map((msg): Content | null => {
        let text = msg.text || '';
        if (!msg.text) {
            if (msg.quiz) text = `[System: A quiz was generated.]`;
            else if (msg.flashcards) text = `[System: Flashcards were generated.]`;
            else if (msg.imageUrl) text = msg.role === 'model' ? `[System: Image generated.]` : `[System: Image sent.]`;
        }
        if (!text.trim()) return null;
        return { role: msg.role, parts: [{ text: text }] };
    }).filter((msg): msg is Content => msg !== null);
};

export const generateTutorResponseStream = async (prompt: string, language: string, history: ChatMessage[], image?: { mimeType: string; data: string; }): Promise<AsyncGenerator<string>> => {
  const userParts: Part[] = [{ text: prompt }];
  if (image) userParts.push({ inlineData: { mimeType: image.mimeType, data: image.data } });
  const contents = [...buildChatHistory(history), { role: 'user', parts: userParts }];
  const responseStream = await ai.models.generateContentStream({
      model: GEMINI_MODEL,
      contents,
      config: { systemInstruction: `You are a friendly personal tutor. Respond in ${language}. No markdown.` }
  });
  async function* streamGenerator() { for await (const chunk of responseStream) yield chunk.text; }
  return streamGenerator();
};

export const generateNoraTextStream = async (session: NoraSession, prompt: string, image?: { mimeType: string; data: string; }): Promise<AsyncGenerator<string>> => {
    const userParts: Part[] = [{ text: prompt }];
    if (image) userParts.push({ inlineData: { mimeType: image.mimeType, data: image.data } });
    const responseStream = await ai.models.generateContentStream({
        model: GEMINI_MODEL,
        contents: [...buildChatHistory(session.history), { role: 'user', parts: userParts }],
        config: { systemInstruction: `You are NORA. Use these notes: ${session.notes}` }
    });
    async function* streamGenerator() { for await (const chunk of responseStream) yield chunk.text; }
    return streamGenerator();
};

export const generateNoraJson = async (session: NoraSession, prompt: string, schema: any, image?: { mimeType: string; data: string; }): Promise<any> => {
    const userParts: Part[] = [{ text: prompt }];
    if (image) userParts.push({ inlineData: { mimeType: image.mimeType, data: image.data } });
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: [...buildChatHistory(session.history), { role: 'user', parts: userParts }],
        config: { systemInstruction: `You are NORA. Use these notes: ${session.notes}`, responseMimeType: 'application/json', responseSchema: schema }
    });
    return JSON.parse(response.text);
};

export const generateImage = async(prompt: string): Promise<string> => {
    const response = await ai.models.generateImages({ model: 'imagen-4.0-generate-001', prompt, config: { numberOfImages: 1, outputMimeType: 'image/png' } });
    return `data:image/png;base64,${response.generatedImages[0].image.imageBytes}`;
};

export const generateNotesFromTranscription = async (transcription: string): Promise<string> => {
    const response = await ai.models.generateContent({ model: GEMINI_MODEL, contents: `Summarize this as notes:\n${transcription}` });
    return response.text;
};

export const explainCode = async (code: string, language: string): Promise<CodeExplanation[]> => {
    const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: `Explain ${language} code:\n${code}`,
        config: { responseMimeType: 'application/json', responseSchema: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { lineNumber: { type: Type.INTEGER }, code: { type: Type.STRING }, explanation: { type: Type.STRING } }, required: ['lineNumber', 'code', 'explanation'] } } }
    });
    return JSON.parse(response.text);
};

// --- RAM AGENT SERVICE ---

const RAM_SYSTEM_INSTRUCTION = `
You are "Ram", a high-performance voice assistant. 
IMPORTANT: You must always respond in TELUGU (తెలుగు) language.

CAPABILITIES:
1. YouTube: Use 'play_song' to play specific videos.
2. Apps: Use 'open_system_app' to open WhatsApp, Maps, Email, Phone, or Calendar.
3. Navigation: Use 'navigate_to_feature' to switch between Tutor, Exam Prep, and Coding sections.
4. Files: Use 'open_system_app' with app_id 'whatsapp' and action 'file_transfer' if the user mentions files/photos.

If a user says "Play [Song]", trigger 'play_song'. 
If a user says "Open WhatsApp", "Navigate me to [Place]", or "Mail [Person]", trigger 'open_system_app'.
If a user says "Go to Tutor", trigger 'navigate_to_feature'.

Always respond politely in Telugu confirming the action.
`;

const playSongTool: FunctionDeclaration = {
    name: "play_song",
    description: "Search and play a video on YouTube.",
    parameters: {
        type: Type.OBJECT,
        properties: { song_name: { type: Type.STRING, description: "Name of the song/video." } },
        required: ["song_name"]
    }
};

const openAppTool: FunctionDeclaration = {
    name: "open_system_app",
    description: "Opens system/native applications or web services.",
    parameters: {
        type: Type.OBJECT,
        properties: {
            app_id: { type: Type.STRING, enum: ['whatsapp', 'maps', 'mail', 'phone', 'calendar'], description: "The app to open." },
            query: { type: Type.STRING, description: "Optional search query, destination, or contact name." },
            action: { type: Type.STRING, enum: ['default', 'file_transfer', 'navigate', 'call'], description: "Specific intent." }
        },
        required: ["app_id"]
    }
};

const navigateTool: FunctionDeclaration = {
    name: "navigate_to_feature",
    description: "Navigates the user to a specific section of the learning platform.",
    parameters: {
        type: Type.OBJECT,
        properties: { feature_id: { type: Type.STRING, enum: ['tutor', 'exam-prep', 'coding-mentor'] } },
        required: ["feature_id"]
    }
};

export const runRamAgent = async (transcript: string) => {
    return await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: transcript,
        config: {
            systemInstruction: RAM_SYSTEM_INSTRUCTION,
            tools: [{ functionDeclarations: [playSongTool, openAppTool, navigateTool] }],
        }
    });
};

import React, { useState, useEffect, useRef } from 'react';
import { runRamAgent } from '../../services/geminiService';
import { useSpeechToText } from '../../hooks/useSpeechToText';
import { MicrophoneIcon } from '../icons/MicrophoneIcon';
import Loader from '../ui/Loader';
import { SparklesIcon } from '../icons/SparklesIcon';
import { FeatureId } from '../../constants';

interface RamAgentProps {
    onNavigate: (featureId: FeatureId) => void;
}

const RamAgent: React.FC<RamAgentProps> = ({ onNavigate }) => {
    const [isProcessing, setIsProcessing] = useState(false);
    const [responseText, setResponseText] = useState<string>('');
    const { isListening, transcript, startListening, stopListening, hasRecognitionSupport } = useSpeechToText();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAgentInteraction = async () => {
        if (!transcript.trim()) return;
        setIsProcessing(true);
        setResponseText(''); 

        try {
            const result = await runRamAgent(transcript);
            const functionCalls = result.functionCalls;

            if (functionCalls && functionCalls.length > 0) {
                for (const call of functionCalls) {
                    const args = call.args as any;

                    if (call.name === 'play_song') {
                        // Using a more direct playback search filter
                        const query = encodeURIComponent(args.song_name);
                        window.open(`https://www.youtube.com/results?search_query=${query}&sp=EgIQAQ%253D%253D`, '_blank');
                    } 

                    else if (call.name === 'open_system_app') {
                        const { app_id, query, action } = args;
                        const encodedQuery = encodeURIComponent(query || '');

                        switch (app_id) {
                            case 'whatsapp':
                                // Try deep link first, then fallback to web
                                window.open(`whatsapp://send?text=${encodedQuery}`, '_blank');
                                setTimeout(() => window.open(`https://web.whatsapp.com/send?text=${encodedQuery}`, '_blank'), 500);
                                if (action === 'file_transfer') {
                                    setTimeout(() => fileInputRef.current?.click(), 2000);
                                }
                                break;
                            case 'maps':
                                window.open(`https://www.google.com/maps/dir/?api=1&destination=${encodedQuery}`, '_blank');
                                break;
                            case 'mail':
                                window.location.href = `mailto:?subject=Message from Ram&body=${encodedQuery}`;
                                break;
                            case 'phone':
                                window.location.href = `tel:${query}`;
                                break;
                            case 'calendar':
                                window.open('https://calendar.google.com', '_blank');
                                break;
                        }
                    } 

                    else if (call.name === 'navigate_to_feature') {
                        const featureIdMap: Record<string, FeatureId> = {
                            'tutor': FeatureId.TUTOR,
                            'exam-prep': FeatureId.EXAM_PREP,
                            'coding-mentor': FeatureId.CODING_MENTOR
                        };
                        if (featureIdMap[args.feature_id]) onNavigate(featureIdMap[args.feature_id]);
                    }
                }
            }

            if (result.text) {
                setResponseText(result.text);
                speakText(result.text);
