    return (
        <div className="mt-2 flex flex-col items-end w-64 z-50 relative group">
            <div className="bg-gradient-to-br from-orange-900 via-red-900 to-black backdrop-blur-xl border border-orange-500/40 p-3 rounded-2xl shadow-2xl w-full ring-1 ring-white/10">
