import React, { useState, useEffect, useRef } from 'react';
import { runRamAgent } from '../../services/geminiService';
import { useSpeechToText } from '../../hooks/useSpeechToText';
import { MicrophoneIcon } from '../icons/MicrophoneIcon';
import Loader from '../ui/Loader';
import { SparklesIcon } from '../icons/SparklesIcon';
import { FeatureId } from '../../constants';

interface RamAgentProps {
    onNavigate: (featureId: FeatureId) => void;
}

const RamAgent: React.FC<RamAgentProps> = ({ onNavigate }) => {
    const [isProcessing, setIsProcessing] = useState(false);
    const [responseText, setResponseText] = useState<string>('');
    const { isListening, transcript, startListening, stopListening, hasRecognitionSupport } = useSpeechToText();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAgentInteraction = async () => {
        if (!transcript.trim()) return;
        setIsProcessing(true);
        setResponseText(''); 

        try {
            const result = await runRamAgent(transcript);
            const functionCalls = result.functionCalls;

            if (functionCalls && functionCalls.length > 0) {
                for (const call of functionCalls) {
                    const args = call.args as any;

                    if (call.name === 'play_youtube') {
                        const query = encodeURIComponent(args.query);
                        // Using sp=EgIQAQ%253D%253D filter to prioritize full videos which often helps with direct playback
                        window.open(`https://www.youtube.com/results?search_query=${query}&sp=EgIQAQ%253D%253D`, '_blank');
                    } 

                    else if (call.name === 'open_system_app') {
                        const { app_id, data } = args;
                        const encodedData = encodeURIComponent(data || '');

                        switch (app_id) {
                            case 'whatsapp':
                                window.open(`whatsapp://send?text=${encodedData}`, '_blank');
                                setTimeout(() => window.open(`https://web.whatsapp.com/send?text=${encodedData}`, '_blank'), 500);
                                break;
                            case 'maps':
                                window.open(`https://www.google.com/maps/search/${encodedData}`, '_blank');
                                break;
                            case 'mail':
                                window.location.href = `mailto:?body=${encodedData}`;
                                break;
                            case 'phone':
                                window.location.href = `tel:${data}`;
                                break;
                            case 'calculator':
                                // Protocol handlers for desktop calculators
                                window.location.href = "calc:"; 
                                break;
                            case 'calendar':
                                window.open('https://calendar.google.com', '_blank');
                                break;
                            case 'settings':
                                window.location.href = "ms-settings:";
                                break;
                            case 'notes':
                                window.location.href = "mobilenotes:";
                                break;
                        }
                    } 

                    else if (call.name === 'web_browser_search') {
                        const query = encodeURIComponent(args.query);
                        window.open(`https://www.google.com/search?q=${query}`, '_blank');
                    }

                    else if (call.name === 'navigate_to_feature') {
                        const featureIdMap: Record<string, FeatureId> = {
                            'tutor': FeatureId.TUTOR,
                            'exam-prep': FeatureId.EXAM_PREP,
                            'coding-mentor': FeatureId.CODING_MENTOR
                        };
                        if (featureIdMap[args.feature_id]) onNavigate(featureIdMap[args.feature_id]);
                    }
                }
            }

            if (result.text) {
                setResponseText(result.text);
                speakText(result.text);
            }
        } catch (error) {
            console.error("Ram Agent Error:", error);
            setResponseText("క్షమించండి, రామ్ విఫలమయ్యాడు.");
        } finally {
            setIsProcessing(false);
        }
    };

    const prevListening = useRef(isListening);
    useEffect(() => {
        if (prevListening.current && !isListening && transcript) handleAgentInteraction();
        prevListening.current = isListening;
    }, [isListening, transcript]);

    const speakText = (text: string) => {
        if ('speechSynthesis' in window) {
            window.speechSynthesis.cancel();
            const utterance = new SpeechSynthesisUtterance(text);
            utterance.lang = 'te-IN';
            window.speechSynthesis.speak(utterance);
        }
    };

    const toggleListening = () => {
        if (isListening) stopListening();
        else {
            setResponseText("రామ్ వింటున్నాడు... చెప్పండి.");
            startListening();
        }
    };

    if (!hasRecognitionSupport) return null;

    return (
        <div className="mt-2 flex flex-col items-end w-64 z-50 relative animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="bg-gradient-to-br from-gray-900 via-indigo-950 to-black backdrop-blur-2xl border border-white/10 p-3 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] w-full ring-1 ring-white/20">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2">
                        <div className="relative">
                            <div className="absolute inset-0 bg-indigo-500 rounded-full blur-md animate-pulse"></div>
                            <div className="relative bg-indigo-600 p-1.5 rounded-full shadow-lg border border-indigo-400">
                                <SparklesIcon className="w-3.5 h-3.5 text-white" />
                            </div>
                        </div>
                        <div className="flex flex-col">
                            <span className="font-black tracking-widest text-indigo-100 text-[10px] uppercase">Ram Agent</span>
                            <div className="flex items-center gap-1">
                                <span className="w-1 h-1 bg-green-500 rounded-full animate-ping"></span>
                                <span className="text-[8px] text-green-400 font-bold uppercase tracking-tighter">System Sync Active</span>
                            </div>
                        </div>
                    </div>
                    {isProcessing && <Loader size="sm" className="text-indigo-400" />}
                </div>

                <div className="bg-black/60 rounded-xl p-3 min-h-[60px] mb-3 border border-white/5 shadow-inner backdrop-grayscale">
                    <p className="text-[11px] leading-snug text-gray-100 font-medium">
                        {isListening ? (
                            <span className="text-indigo-300 italic">గమనిస్తున్నాను...</span>
                        ) : (
                            responseText || "నమస్కారం! నేను రామ్. నేను మీకు ఎలా సహాయం చేయగలను?"
                        )}
                    </p>
                </div>

                <button
                    onClick={toggleListening}
                    className={`group relative overflow-hidden p-3 rounded-xl transition-all duration-500 shadow-xl flex items-center gap-3 w-full justify-center
                        ${isListening 
                            ? 'bg-red-600 text-white ring-4 ring-red-500/20' 
                            : 'bg-white text-black hover:bg-gray-100 active:scale-95'
                        }`}
                >
                    <MicrophoneIcon className={`w-5 h-5 transition-transform duration-300 ${isListening ? 'animate-bounce' : 'group-hover:scale-110'}`} />
                    <span className="text-xs font-black uppercase tracking-[0.2em]">{isListening ? 'STOP' : 'ACTIVATE RAM'}</span>

                    {/* Animated background glow on hover */}
                    {!isListening && (
                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                    )}
                </button>
            </div>
            <input type="file" ref={fileInputRef} className="hidden" />
        </div>
    );
};

export default RamAgent;

