import { SpeakerWaveIcon } from '../icons/SpeakerWaveIcon';

const decodeBase64 = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
};

async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
            channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
    }
    return buffer;
}

const CodingMentor: React.FC = () => {
  const [code, setCode] = useState('');
  const [language, setLanguage] = useState(CODING_LANGUAGES[0].value);
  const [explanation, setExplanation] = useState<CodeExplanation[] | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [playingIndex, setPlayingIndex] = useState<number | null>(null);

  // Chat specific state
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    { role: 'model', text: "Hello! I'm your Coding Mentor. Paste some code on the right to explain it, or ask me to write some code for you here!" }
  ]);
  const [chatInput, setChatInput] = useState('');

  const { isListening, transcript, startListening, stopListening, hasRecognitionSupport } = useSpeechToText();
  const initialChatInputRef = useRef('');
  const audioContextRef = useRef<AudioContext | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory]);

  const handleToggleListening = () => {
    if (isListening) {
      stopListening();
    } else {
      initialChatInputRef.current = chatInput;
      startListening();
    }
  };

  useEffect(() => {
    if (isListening) {
      setChatInput(initialChatInputRef.current + (initialChatInputRef.current ? ' ' : '') + transcript);
    }
  }, [transcript, isListening]);

  const handleExplain = async () => {
    if (!code.trim() || isLoading) return;
    setIsLoading(true);
    setError(null);
    setExplanation(null);
    try {
      const result = await explainCode(code, language);
      setExplanation(result);
    } catch (err) {
      console.error(err);
      setError('Failed to get explanation. The code might be invalid or the model is unavailable.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleChatSend = async () => {
    if (!chatInput.trim() || isChatLoading) return;

    const userPrompt = chatInput;
    setChatInput('');
    setIsChatLoading(true);

    setChatHistory(prev => [...prev, { role: 'user', text: userPrompt }, { role: 'model', text: '', isPartial: true }]);

    try {
        const stream = await generateCodingMentorChatStream(userPrompt, code, language, chatHistory);
        let fullText = '';
        for await (const chunk of stream) {
            fullText += chunk;
            setChatHistory(prev => {
                const newHistory = [...prev];
                const last = newHistory[newHistory.length - 1];
                if (last.role === 'model') last.text = fullText;
                return newHistory;
            });
        }

        // Finalize
        setChatHistory(prev => {
            const newHistory = [...prev];
            const last = newHistory[newHistory.length - 1];
            if (last.role === 'model') last.isPartial = false;
            return newHistory;
        });

    } catch (err) {
        console.error("Chat error:", err);
        setChatHistory(prev => [...prev, { role: 'model', text: "Sorry, I had trouble processing that request." }]);
    } finally {
        setIsChatLoading(false);
    }
  };

  const handleApplyToEditor = (text: string) => {
    // Basic extraction of markdown code blocks
    const codeMatch = text.match(/```(?:\w+)?\n([\s\S]*?)```/);
    if (codeMatch && codeMatch[1]) {
        setCode(codeMatch[1].trim());
    } else {
        // If no markdown, just take the whole thing if it looks like code, or notify
        setCode(text.trim());
    }
  };

  const handlePlayVoice = async (text: string, index: number) => {
    if (playingIndex !== null) return;
    setPlayingIndex(index);

    try {
        const base64Audio = await generateTutorVoice(text, 'Zephyr');
        if (!base64Audio) {
            setPlayingIndex(null);
            return;
        }

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }

        const ctx = audioContextRef.current;
        const audioData = decodeBase64(base64Audio);
        const audioBuffer = await decodeAudioData(audioData, ctx, 24000, 1);

        const source = ctx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(ctx.destination);
        source.onended = () => setPlayingIndex(null);
        source.start();
    } catch (err) {
        console.error("TTS generation error:", err);
        setPlayingIndex(null);
    }
  };

  return (
    <div className="flex flex-col gap-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-semibold text-gray-200">Coding Mentor</h2>
        <div className="flex gap-2">
           <Select 
            value={language}
            onChange={e => setLanguage(e.target.value)}
            options={CODING_LANGUAGES}
            className="w-40"
          />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 h-[70vh]">
        {/* Chat Pane */}
        <Card className="flex flex-col h-full bg-gray-900/40 border-gray-700/50">
           <div className="flex-grow overflow-y-auto space-y-4 mb-4 pr-2">
               {chatHistory.map((msg, i) => (
                   <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                       <div className={`p-3 rounded-2xl max-w-[90%] text-sm ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-200 border border-gray-700'}`}>
                           <p className="whitespace-pre-wrap leading-relaxed">{msg.text}</p>
                           {msg.role === 'model' && !msg.isPartial && msg.text?.includes('```') && (
                               <button 
                                    onClick={() => handleApplyToEditor(msg.text!)}
                                    className="mt-2 text-[10px] font-bold text-cyan-400 hover:text-cyan-300 uppercase tracking-widest border border-cyan-400/30 px-2 py-1 rounded bg-cyan-950/20"
                               >
                                   Apply Code to Editor
                               </button>
                           )}
                       </div>
                   </div>
               ))}
               <div ref={chatEndRef} />
           </div>

           <div className="flex gap-2 relative">
                <input 
                    type="text"
                    value={chatInput}
                    onChange={e => setChatInput(e.target.value)}
                    onKeyPress={e => e.key === 'Enter' && handleChatSend()}
                    placeholder="Write a binary search..."
                    className="flex-grow bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    disabled={isChatLoading}
                />
                {hasRecognitionSupport && (
                    <button
                        onClick={handleToggleListening}
                        className={`absolute right-16 top-3 p-1 rounded-full text-gray-500 hover:text-white transition-colors ${isListening ? 'text-red-400 animate-pulse' : ''}`}
                    >
                        <MicrophoneIcon className="h-5 w-5" />
                    </button>
                )}
                <Button onClick={handleChatSend} disabled={isChatLoading || !chatInput.trim()} className="rounded-xl px-6">
                    {isChatLoading ? <Loader size="sm" /> : 'Ask'}
                </Button>
           </div>
        </Card>

        {/* Editor & Explanation Pane */}
        <div className="flex flex-col h-full space-y-4">
          <div className="relative flex-grow flex flex-col">
            <TextArea
              value={code}
              onChange={(e) => setCode(e.target.value)}
              placeholder={`// Code will appear here or paste your own...`}
              className="flex-grow font-mono text-xs bg-gray-900 border-gray-700 resize-none rounded-2xl p-4 leading-relaxed scrollbar-thin scrollbar-thumb-gray-700"
              disabled={isLoading}
            />
            <div className="flex gap-2 mt-4">
                 <Button onClick={handleExplain} disabled={isLoading || !code.trim()} className="flex-grow py-3 rounded-2xl bg-indigo-600 hover:bg-indigo-500 shadow-lg shadow-indigo-950/50">
                    {isLoading ? <div className="flex items-center gap-2"><Loader size="sm" /><span>Analyzing...</span></div> : 'Analyze & Explain Code'}
                </Button>
                <Button onClick={() => setCode('')} variant="secondary" className="px-6 rounded-2xl bg-gray-700 hover:bg-gray-600">
                    Clear
                </Button>
            </div>
          </div>

          <Card className="h-64 overflow-y-auto bg-gray-800/40 border-gray-700/30">
            <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-3">Line-by-Line Breakdown</h3>
            {explanation ? (
              <div className="font-mono text-xs space-y-4">
                {explanation.map((item, index) => (
                  <div key={index} className="relative border-l-2 border-indigo-500/30 pl-3 pb-3 group">
                    <pre className="text-purple-300 opacity-60 mb-1"><code>{`Line ${item.lineNumber}: ${item.code.substring(0, 50)}${item.code.length > 50 ? '...' : ''}`}</code></pre>
                    <div className="pr-10">
                        <p className="text-gray-300 leading-relaxed">{item.explanation}</p>
                    </div>
                    <button 
                        onClick={() => handlePlayVoice(item.explanation, index)}
                        className={`absolute right-0 top-1/2 -translate-y-1/2 p-2 rounded-full transition-all duration-300 ${playingIndex === index ? 'text-indigo-400 animate-pulse bg-gray-900 shadow-lg' : 'text-gray-600 hover:text-indigo-400 hover:bg-gray-900 opacity-0 group-hover:opacity-100'}`}
                        disabled={playingIndex !== null}
                    >
                        {playingIndex === index ? <Loader size="sm" /> : <SpeakerWaveIcon className="h-4 w-4" />}
                    </button>
                  </div>
                ))}
              </div>
            ) : (
                <div className="flex flex-col items-center justify-center h-full text-gray-600 italic text-sm">
                    {isLoading ? 'Mentor is reading your code...' : 'Explanations will appear here after analysis.'}
                </div>
            )}
          </Card>
        </div>
      </div>
    </div>
  );
};

