// FIX: Import React to provide the React namespace for types like React.Dispatch.
import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Blob } from '@google/genai';
import { ChatMessage } from '../types';

// FIX: Add global declaration for webkitAudioContext to fix TypeScript errors and ensure cross-browser compatibility.
declare global {
  interface Window {
    webkitAudioContext: typeof AudioContext;
  }
}

// FIX: Initialize the GoogleGenAI client with the API key from environment variables as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// FIX: Define LiveSession type helper since it's not exported directly in the current SDK version.
type LiveSession = Awaited<ReturnType<InstanceType<typeof GoogleGenAI>['live']['connect']>>;

// Helper function to resample an audio buffer to a target sample rate.
const resampleBuffer = (inputBuffer: Float32Array, fromSampleRate: number, toSampleRate: number): Float32Array => {
    if (fromSampleRate === toSampleRate) {
        return inputBuffer;
    }

    const inputLength = inputBuffer.length;
    const outputLength = Math.round(inputLength * toSampleRate / fromSampleRate);
    const outputBuffer = new Float32Array(outputLength);

    if (inputLength === 0 || outputLength === 0) {
        return outputBuffer;
    }

    if (outputLength === 1) {
        let sum = 0;
        for (let i = 0; i < inputLength; i++) {
            sum += inputBuffer[i];
        }
        outputBuffer[0] = sum / inputLength;
        return outputBuffer;
    }

    const ratio = (inputLength - 1) / (outputLength - 1);

    for (let i = 0; i < outputLength; i++) {
        const index = i * ratio;
        const low = Math.floor(index);
        const high = Math.ceil(index);

        if (low === high) {
            outputBuffer[i] = inputBuffer[low];
        } else {
            const weight = index - low;
            outputBuffer[i] = inputBuffer[low] * (1 - weight) + inputBuffer[high] * weight;
        }
    }
    return outputBuffer;
};


// Base64 and Audio Decoding/Encoding Helpers
const decode = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

const encode = (bytes: Uint8Array) => {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
};

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export type ConversationState = 'idle' | 'listening' | 'processing' | 'speaking';

interface UseVoiceConversationProps {
  systemInstruction: string;
  onUpdateHistory: React.Dispatch<React.SetStateAction<ChatMessage[]>>;
  initialHistory: ChatMessage[];
  voice: string;
}

export const useVoiceConversation = ({ systemInstruction, onUpdateHistory, voice }: UseVoiceConversationProps) => {
  const [conversationState, setConversationState] = useState<ConversationState>('idle');
  const [error, setError] = useState<string | null>(null);

  const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const mediaStreamSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const nextStartTimeRef = useRef(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isStoppingRef = useRef(false);

  const cleanup = useCallback(async () => {
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }
    if (mediaStreamSourceRef.current) {
        mediaStreamSourceRef.current.disconnect();
        mediaStreamSourceRef.current = null;
    }
    if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
    }
    audioSourcesRef.current.forEach(source => source.stop());
    audioSourcesRef.current.clear();
    nextStartTimeRef.current = 0;

    const closePromises = [];
    if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
        closePromises.push(inputAudioContextRef.current.close());
    }
    if (outputAudioContextRef.current && outputAudioContextRef.current.state !== 'closed') {
        closePromises.push(outputAudioContextRef.current.close());
    }

    if(closePromises.length > 0) {
        await Promise.all(closePromises.map(p => p.catch(console.error)));
    }

    setConversationState('idle');
  }, []);

  const stopConversation = useCallback(async () => {
    if (isStoppingRef.current) {
      return;
    }
    isStoppingRef.current = true;

    if (sessionPromiseRef.current) {
      try {
        const session = await sessionPromiseRef.current;
        session.close();
      } catch (e) {
        console.error("Error closing session:", e);
      }
      sessionPromiseRef.current = null;
    }
    await cleanup();
    isStoppingRef.current = false;
  }, [cleanup]);


  const startConversation = useCallback(async () => {
    if (conversationState !== 'idle') return;

    setError(null);
    setConversationState('listening');

    try {
        inputAudioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        outputAudioContextRef.current = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });

        mediaStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

        let currentInputTranscription = '';
        let currentOutputTranscription = '';

        sessionPromiseRef.current = ai.live.connect({
            // Correct model for real-time audio/video conversation as per guidelines
            model: 'gemini-2.5-flash-native-audio-preview-12-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice } } },
                systemInstruction,
                outputAudioTranscription: {},
                inputAudioTranscription: {},
            },
            callbacks: {
                onopen: () => {
                    const source = inputAudioContextRef.current!.createMediaStreamSource(mediaStreamRef.current!);
                    mediaStreamSourceRef.current = source;
                    const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(1024, 1, 1);
                    scriptProcessorRef.current = scriptProcessor;

                    scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                        const inputBuffer = audioProcessingEvent.inputBuffer;
                        const rawPcmData = inputBuffer.getChannelData(0);
                        const resampledData = resampleBuffer(rawPcmData, inputBuffer.sampleRate, 16000);
                        const pcmBlob = createBlob(resampledData);

                        if (sessionPromiseRef.current) {
                           sessionPromiseRef.current.then((session) => {
                             session.sendRealtimeInput({ media: pcmBlob });
                           });
                        }
                    };
                    source.connect(scriptProcessor);
                    scriptProcessor.connect(inputAudioContextRef.current!.destination);
                },
                onmessage: async (message: LiveServerMessage) => {
                    if (message.serverContent?.inputTranscription) {
                        currentInputTranscription += message.serverContent.inputTranscription.text;
                        onUpdateHistory(prevHistory => {
                            const newHistory = [...prevHistory];
                            const lastMsg = newHistory[newHistory.length - 1];
                            if (lastMsg?.role === 'user' && lastMsg.isPartial) {
                                lastMsg.text = currentInputTranscription;
                            } else {
                                newHistory.push({ role: 'user', text: currentInputTranscription, isPartial: true });
                            }
                            return newHistory;
                        });
                    }
                    if (message.serverContent?.outputTranscription) {
                        setConversationState('speaking');
                        currentOutputTranscription += message.serverContent.outputTranscription.text;
                        onUpdateHistory(prevHistory => {
                            const newHistory = [...prevHistory];
                            const lastMsg = newHistory[newHistory.length - 1];
                            if (lastMsg?.role === 'model' && lastMsg.isPartial) {
                                lastMsg.text = currentOutputTranscription;
                            } else {
                                newHistory.push({ role: 'model', text: currentOutputTranscription, isPartial: true });
                            }
                            return newHistory;
                        });
                    }
                    if (message.serverContent?.turnComplete) {
                        onUpdateHistory(prevHistory => {
                            const newHistory = [...prevHistory];
                            const finalUserMsg = newHistory.find(m => m.role === 'user' && m.isPartial);
                            if (finalUserMsg) finalUserMsg.isPartial = false;

                            const finalModelMsg = newHistory.find(m => m.role === 'model' && m.isPartial);
                            if (finalModelMsg) finalModelMsg.isPartial = false;

                            return newHistory;
                        });

                        currentInputTranscription = '';
                        currentOutputTranscription = '';
                        setConversationState('listening');
                    }

                    const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                    if (base64Audio && outputAudioContextRef.current) {
                        const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContextRef.current, 24000, 1);
                        const source = outputAudioContextRef.current.createBufferSource();
                        source.buffer = audioBuffer;
                        source.connect(outputAudioContextRef.current.destination);

                        source.addEventListener('ended', () => {
                            audioSourcesRef.current.delete(source);
                        });

                        const currentTime = outputAudioContextRef.current.currentTime;
                        const startTime = Math.max(currentTime, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + audioBuffer.duration;
                        audioSourcesRef.current.add(source);
                    }
                },
                onerror: (e: ErrorEvent) => {
                    console.error("Session error:", e);
                    setError('A connection error occurred.');
                    stopConversation();
                },
                onclose: (e: CloseEvent) => {
                    stopConversation();
                },
            },
        });
        await sessionPromiseRef.current;
    } catch (e) {
        console.error("Failed to start conversation:", e);
        setError('Could not access microphone. Please check permissions.');
        cleanup();
    }
  }, [conversationState, systemInstruction, onUpdateHistory, cleanup, stopConversation, voice]);

  useEffect(() => {
      return () => {
          stopConversation();
      }
  }, [stopConversation]);

  return { conversationState, error, startConversation, stopConversation };
};

import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';

interface User {
  name: string;
  email: string;
}

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  loginStep: 'login' | 'otp';
  initiateLogin: (email: string, password: string) => void;
  verifyOtp: (otp: string) => boolean;
  logout: () => void;
  resendOtp: () => void;
  currentEmail: string;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const AUTH_STORAGE_KEY = 'study-buddy-user-session';

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [loginStep, setLoginStep] = useState<'login' | 'otp'>('login');
  const [currentEmail, setCurrentEmail] = useState('');
  const [generatedOtp, setGeneratedOtp] = useState('');

  useEffect(() => {
    try {
      const storedUser = localStorage.getItem(AUTH_STORAGE_KEY);
      if (storedUser) {
        setUser(JSON.parse(storedUser));
      }
    } catch (error) {
      console.error("Failed to parse user from localStorage", error);
    } finally {
        setIsLoading(false);
    }
  }, []);

  const initiateLogin = (email: string, password: string) => {
    // In a real app, you'd validate credentials with a backend here
    setCurrentEmail(email);
    const mockOtp = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(mockOtp);
    // Log OTP to console for the user since we don't have a real email server
    console.log(`[Study Buddy] Your Real-time OTP is: ${mockOtp}`);
    setLoginStep('otp');
  };

  const verifyOtp = (otp: string): boolean => {
    if (otp === generatedOtp) {
      const nameFromEmail = currentEmail.split('@')[0];
      const newUser = { name: nameFromEmail, email: currentEmail };
      setUser(newUser);
      localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(newUser));
      setLoginStep('login');
      return true;
    }
    return false;
  };

  const resendOtp = () => {
    const mockOtp = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(mockOtp);
    console.log(`[Study Buddy] Your NEW Real-time OTP is: ${mockOtp}`);
  };

  const logout = () => {
    setUser(null);
    setLoginStep('login');
    localStorage.removeItem(AUTH_STORAGE_KEY);
  };

  return (
    <AuthContext.Provider value={{ 
        user, 
        isLoading, 
        loginStep, 
        initiateLogin, 
        verifyOtp, 
        logout, 
        resendOtp,
        currentEmail 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import Button from '../ui/Button';
import { SparklesIcon } from '../icons/SparklesIcon';
import { ArrowsPointingOutIcon } from '../icons/ArrowsPointingOutIcon';
import { ArrowsPointingInIcon } from '../icons/ArrowsPointingInIcon';
import Loader from '../ui/Loader';

const LandingPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [error, setError] = useState('');
  const [timer, setTimer] = useState(30);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const { loginStep, initiateLogin, verifyOtp, resendOtp, currentEmail } = useAuth();
  const otpRefs = useRef<(HTMLInputElement | null)[]>([]);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    let interval: any;
    if (loginStep === 'otp' && timer > 0) {
      interval = setInterval(() => setTimer((t) => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loginStep, timer]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
    } else {
      document.exitFullscreen();
    }
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (!email.includes('@')) {
      setError('Please enter a valid Gmail address.');
      return;
    }
    if (password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }
    setIsSubmitting(true);
    // Simulate network delay
    setTimeout(() => {
      initiateLogin(email, password);
      setIsSubmitting(false);
      setTimer(30);
    }, 1000);
  };

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      otpRefs.current[index + 1]?.focus();
    }
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      otpRefs.current[index - 1]?.focus();
    }
  };

  const handleVerifyOtp = () => {
    const fullOtp = otp.join('');
    if (fullOtp.length !== 6) return;

    setIsSubmitting(true);
    setTimeout(() => {
      const success = verifyOtp(fullOtp);
      if (!success) {
        setError('Invalid OTP. Please try again.');
        setOtp(['', '', '', '', '', '']);
        otpRefs.current[0]?.focus();
      }
      setIsSubmitting(false);
    }, 800);
  };

  const handleResend = () => {
    if (timer > 0) return;
    resendOtp();
    setTimer(30);
    setError('A new OTP has been sent.');
  };

  return (
    <div className="min-h-screen bg-[#0a0a0c] text-gray-100 font-sans flex flex-col items-center justify-center p-4 relative overflow-hidden">
      {/* Dynamic Background */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none opacity-40">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600/20 blur-[120px] rounded-full animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-indigo-600/20 blur-[150px] rounded-full"></div>
      </div>

      <div className="absolute top-6 right-6 z-50">
        <button
          onClick={toggleFullscreen}
          className="p-3 bg-white/5 hover:bg-white/10 text-gray-400 hover:text-white rounded-2xl transition-all border border-white/5 backdrop-blur-xl"
        >
          {isFullscreen ? <ArrowsPointingInIcon className="h-6 w-6" /> : <ArrowsPointingOutIcon className="h-6 w-6" />}
        </button>
      </div>

      <div className="text-center max-w-lg w-full z-10 space-y-8">
        <div className="space-y-2">
            <div className="flex items-center justify-center gap-4 mb-2">
                <div className="p-3 bg-gradient-to-br from-purple-500 to-indigo-600 rounded-2xl shadow-2xl shadow-purple-500/20">
                    <SparklesIcon className="text-white h-8 w-8" />
                </div>
                <h1 className="text-5xl sm:text-6xl font-black text-white tracking-tight">
                  Study Buddy
                </h1>
            </div>
            <p className="text-indigo-400 font-bold uppercase tracking-[0.3em] text-xs">AI Learning Platform</p>
            <p className="text-2xl text-gray-400 font-medium italic">"Study Smarter, Not Harder"</p>
        </div>

        <div className="bg-white/5 border border-white/10 backdrop-blur-2xl rounded-[2.5rem] p-8 sm:p-10 shadow-2xl">
          {loginStep === 'login' ? (
            <form onSubmit={handleLoginSubmit} className="space-y-6">
              <h3 className="text-xl font-bold text-white mb-6">Welcome Back</h3>
              <div className="space-y-4">
                <div className="text-left">
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Email Address</label>
                    <input
                      type="email"
                      required
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
