const LandingPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [error, setError] = useState('');
  const [timer, setTimer] = useState(30);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showOtpToast, setShowOtpToast] = useState(false);
  const [lastGeneratedOtp, setLastGeneratedOtp] = useState('');

  const { loginStep, initiateLogin, verifyOtp, resendOtp, currentEmail } = useAuth();
  const otpRefs = useRef<(HTMLInputElement | null)[]>([]);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    let interval: any;
    if (loginStep === 'otp' && timer > 0) {
      interval = setInterval(() => setTimer((t) => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loginStep, timer]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
    } else {
      document.exitFullscreen();
    }
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (!email.includes('@')) {
      setError('Please enter a valid Gmail address.');
      return;
    }
    if (password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }
    setIsSubmitting(true);

    // Simulate network delay
    setTimeout(() => {
      initiateLogin(email, password);
      setIsSubmitting(false);
      setTimer(30);

      // In a real app, the server sends the email. 
      // Here we grab the OTP from the context/console logic to show it to the user.
      // We know the logic in AuthContext generates it, so we'll simulate the "arrival"
      // by finding it (usually we'd get this from the state but for demo we can trigger a visual)
      // Since initiateLogin is a void, we'll wait for the step change.
    }, 1000);
  };

  // Watch for step change to trigger the simulated notification
  useEffect(() => {
    if (loginStep === 'otp') {
      // Small delay to simulate "delivery" time
      const timeout = setTimeout(() => {
        setShowOtpToast(true);
        // Extract OTP from console is not possible, so we assume the user checks console 
        // OR we can improve AuthContext to expose it. 
        // For now, let's make the notification explicitly helpful.
      }, 1500);
      return () => clearTimeout(timeout);
    } else {
      setShowOtpToast(false);
    }
  }, [loginStep]);

  const handleOtpChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      otpRefs.current[index + 1]?.focus();
    }
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      otpRefs.current[index - 1]?.focus();
    }
  };

  const handleVerifyOtp = () => {
    const fullOtp = otp.join('');
    if (fullOtp.length !== 6) return;

    setIsSubmitting(true);
    setTimeout(() => {
      const success = verifyOtp(fullOtp);
      if (!success) {
        setError('Invalid OTP. Please check the notification or console.');
        setOtp(['', '', '', '', '', '']);
        otpRefs.current[0]?.focus();
      }
      setIsSubmitting(false);
    }, 800);
  };

  const handleResend = () => {
    if (timer > 0) return;
    resendOtp();
    setTimer(30);
    setShowOtpToast(false);
    setTimeout(() => setShowOtpToast(true), 500);
    setError('A new OTP has been sent.');
  };

  return (
    <div className="min-h-screen bg-[#0a0a0c] text-gray-100 font-sans flex flex-col items-center justify-center p-4 relative overflow-hidden">

