                    <SparklesIcon className="h-6 w-6 text-white" />
                </div>
                <div className="flex-grow">
                    <p className="text-[10px] font-black uppercase tracking-widest text-indigo-200">New Message</p>
                    <p className="text-sm font-medium text-white">Your Study Buddy verification code is arriving. Check your console/storage or wait for sync.</p>
                </div>
                <button onClick={() => setShowOtpToast(false)} className="text-white/60 hover:text-white">
                    ✕
                </button>
            </div>
            <div className="mt-2 bg-white text-indigo-950 px-4 py-2 rounded-2xl text-center font-black text-xl shadow-xl animate-pulse">
                Check Console (F12) for Code
            </div>
        </div>
      )}

