      <div className="absolute top-6 right-6 z-50">
        <button
          onClick={toggleFullscreen}
          className="p-3 bg-white/5 hover:bg-white/10 text-gray-400 hover:text-white rounded-2xl transition-all border border-white/5 backdrop-blur-xl"
        >
          {isFullscreen ? <ArrowsPointingInIcon className="h-6 w-6" /> : <ArrowsPointingOutIcon className="h-6 w-6" />}
        </button>
      </div>

      <div className="text-center max-w-lg w-full z-10 space-y-8">
