            <p className="text-indigo-400 font-bold uppercase tracking-[0.3em] text-xs">AI Learning Platform</p>
            <p className="text-2xl text-gray-400 font-medium italic">"Study Smarter, Not Harder"</p>
        </div>

        <div className="bg-white/5 border border-white/10 backdrop-blur-2xl rounded-[2.5rem] p-8 sm:p-10 shadow-2xl">
          {loginStep === 'login' ? (
            <form onSubmit={handleLoginSubmit} className="space-y-6">
              <h3 className="text-xl font-bold text-white mb-6">Welcome Back</h3>
              <div className="space-y-4">
                <div className="text-left">
