import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { User } from '../types';

interface UserStats {
  totalMinutes: number;
  flashcardsFlipped: number;
  quizCorrect: number;
  quizTotal: number;
}

interface AuthContextType {
  user: User | null;
  stats: UserStats;
  isLoading: boolean;
  initiateLogin: (email: string, password: string) => void;
  updateProfile: (name: string, avatar?: string) => void;
  trackFlashcardFlip: () => void;
  trackQuizResult: (isCorrect: boolean) => void;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const AUTH_STORAGE_KEY = 'study-buddy-user-session-v4';
const STATS_STORAGE_KEY = 'study-buddy-user-stats-v4';

const INITIAL_STATS: UserStats = {
  totalMinutes: 0,
  flashcardsFlipped: 0,
  quizCorrect: 0,
  quizTotal: 0,
};

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [stats, setStats] = useState<UserStats>(INITIAL_STATS);
  const [isLoading, setIsLoading] = useState(true);

  // Load User and Stats
  useEffect(() => {
    try {
      const storedUser = localStorage.getItem(AUTH_STORAGE_KEY);
      const storedStats = localStorage.getItem(STATS_STORAGE_KEY);

      if (storedUser) setUser(JSON.parse(storedUser));
      if (storedStats) setStats(JSON.parse(storedStats));
    } catch (error) {
      console.error("Auth hydration error", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Persist Stats whenever they change
  useEffect(() => {
    if (user) {
      localStorage.setItem(STATS_STORAGE_KEY, JSON.stringify(stats));
    }
  }, [stats, user]);

  // Track session time (increments every minute)
  useEffect(() => {
    if (!user) return;

    const interval = setInterval(() => {
      setStats(prev => ({
        ...prev,
        totalMinutes: prev.totalMinutes + 1
      }));
    }, 60000);

    return () => clearInterval(interval);
  }, [user]);

  const initiateLogin = (email: string, password: string) => {
    const nameFromEmail = email.split('@')[0];
    const newUser = { 
      name: nameFromEmail.charAt(0).toUpperCase() + nameFromEmail.slice(1), 
      email,
      avatar: undefined 
    };
    setUser(newUser);
    localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(newUser));
  };

  const updateProfile = (name: string, avatar?: string) => {
    if (!user) return;
    const updatedUser = { ...user, name, avatar: avatar || user.avatar };
    setUser(updatedUser);
    localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(updatedUser));
  };

  const trackFlashcardFlip = () => {
    setStats(prev => ({ ...prev, flashcardsFlipped: prev.flashcardsFlipped + 1 }));
  };

  const trackQuizResult = (isCorrect: boolean) => {
    setStats(prev => ({
      ...prev,
      quizCorrect: prev.quizCorrect + (isCorrect ? 1 : 0),
      quizTotal: prev.quizTotal + 1
    }));
  };

  const logout = () => {
    setUser(null);
    setStats(INITIAL_STATS);
    localStorage.removeItem(AUTH_STORAGE_KEY);
    localStorage.removeItem(STATS_STORAGE_KEY);
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      stats, 
      isLoading, 
      initiateLogin, 
      updateProfile, 
      trackFlashcardFlip, 
      trackQuizResult, 
      logout 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

